@page "/apply"
@rendermode InteractiveServer
@using sv_fa3ff468c69344bb88e04db9a79ad9e1.Models
@using sv_fa3ff468c69344bb88e04db9a79ad9e1.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1 class="mb-4">Job Application</h1>

@if (_submitted)
{
    <div class="alert alert-success text-center py-5">
        <h2>🎉 Application Submitted!</h2>
        <p class="lead mt-3">Your application has been received.</p>
        <p>Application ID: <strong>@_applicationId</strong></p>
    </div>
}
else
{
    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="card mt-4">
        <div class="card-body">
            @switch (_currentStep)
            {
                case 1:
                    <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                      FullNameChanged="v => _fullName = v"
                                      EmailChanged="v => _email = v"
                                      PhoneChanged="v => _phone = v"
                                      AddressChanged="v => _address = v"
                                      ValidationError="@_validationError"
                                      OnNext="HandlePersonalInfoNext" />
                    break;

                case 2:
                    <StepWorkHistory WorkEntries="_workEntries"
                                     ValidationError="@_validationError"
                                     OnBack="GoBack"
                                     OnNext="HandleWorkHistoryNext" />
                    break;

                case 3:
                    <StepReferences References="_references"
                                    ValidationError="@_validationError"
                                    OnBack="GoBack"
                                    OnNext="HandleReferencesNext" />
                    break;

                case 4:
                    <StepCoverLetter @bind-CoverLetter="_coverLetter"
                                     MaxLength="2000"
                                     ValidationError="@_validationError"
                                     OnBack="GoBack"
                                     OnNext="HandleCoverLetterNext" />
                    break;

                case 5:
                    <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                WorkEntries="_workEntries"
                                References="_references"
                                CoverLetter="@_coverLetter"
                                IsSubmitting="_isSubmitting"
                                SubmitError="@_submitError"
                                OnEdit="GoToStep"
                                OnSubmit="HandleSubmit" />
                    break;
            }
        </div>
    </div>
}

@code {
    private int _currentStep = 1;
    private readonly HashSet<int> _completedSteps = new();
    private string? _validationError;

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string _coverLetter = "";

    // Submit
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _submitError;

    private void GoToStep(int step)
    {
        if (step < _currentStep || _completedSteps.Contains(step))
        {
            _validationError = null;
            _currentStep = step;
        }
    }

    private void GoBack()
    {
        _validationError = null;
        _currentStep--;
    }

    private void AdvanceTo(int step)
    {
        _completedSteps.Add(_currentStep);
        _validationError = null;
        _currentStep = step;
    }

    private async Task HandlePersonalInfoNext()
    {
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _validationError = "All fields are required.";
            return;
        }

        var emailValid = await ApplicationService.ValidateEmailAsync(_email);
        if (!emailValid)
        {
            _validationError = "Please enter a valid email address.";
            return;
        }

        AdvanceTo(2);
    }

    private void HandleWorkHistoryNext()
    {
        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                _validationError = "Company, job title, and start date are required for each entry.";
                return;
            }
        }
        AdvanceTo(3);
    }

    private void HandleReferencesNext()
    {
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _validationError = "All fields are required for each reference.";
                return;
            }
        }
        AdvanceTo(4);
    }

    private void HandleCoverLetterNext()
    {
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _validationError = "Please write a cover letter.";
            return;
        }
        AdvanceTo(5);
    }

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        _submitError = null;

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

@{
    var steps = new[] { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
}

<nav aria-label="Application steps">
    <ol class="step-indicator d-flex list-unstyled mb-0 p-3 bg-light rounded">
        @for (int i = 0; i < steps.Length; i++)
        {
            var stepNum = i + 1;
            var isCompleted = CompletedSteps.Contains(stepNum);
            var isCurrent = stepNum == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(!isCurrent && !isCompleted ? "dimmed" : "")">
                @if (isClickable)
                {
                    <a href="" @onclick="() => OnStepClicked.InvokeAsync(stepNum)" @onclick:preventDefault class="text-decoration-none">
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            @if (isCompleted && !isCurrent)
                            {
                                <span>✓</span>
                            }
                            else
                            {
                                @stepNum
                            }
                        </span>
                        <div class="step-label small">@steps[i]</div>
                    </a>
                }
                else
                {
                    <span>
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            @if (isCompleted && !isCurrent)
                            {
                                <span>✓</span>
                            }
                            else
                            {
                                @stepNum
                            }
                        </span>
                        <div class="step-label small">@steps[i]</div>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    counter-reset: step;
    gap: 0.25rem;
}

.step-item {
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 16px;
    left: -50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.active + .step-item::before {
    background-color: #0d6efd;
}

.step-circle {
    width: 34px;
    height: 34px;
    font-size: 0.85rem;
    font-weight: 600;
    position: relative;
    z-index: 1;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
}

.step-item.dimmed .step-circle {
    background-color: #dee2e6;
    color: #6c757d;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.completed a:hover .step-circle {
    background-color: #146c43;
}

@using static sv_fa3ff468c69344bb88e04db9a79ad9e1.Components.Pages.Apply.Apply

<h4>Work History</h4>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < WorkEntries.Count; i++)
{
    var index = i;
    var entry = WorkEntries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (WorkEntries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Title" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                </div>
                <div class="col-md-4 d-flex align-items-end pb-2">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="current-@index" @bind="entry.IsCurrent" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => WorkEntries.Add(new WorkEntryModel());
    private void RemoveEntry(int index) => WorkEntries.RemoveAt(index);
}

@using static sv_fa3ff468c69344bb88e04db9a79ad9e1.Components.Pages.Apply.Apply

<h4>References</h4>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Name" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Relationship" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="reference.Email" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="reference.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference() => References.Add(new ReferenceModel());
    private void RemoveReference(int index) => References.RemoveAt(index);
}

@using static sv_fa3ff468c69344bb88e04db9a79ad9e1.Components.Pages.Apply.Apply

<h4>Review & Submit</h4>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<!-- Personal Info -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <a href="" @onclick="() => OnEdit.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        <div class="row">
            <div class="col-md-6"><strong>Name:</strong> @FullName</div>
            <div class="col-md-6"><strong>Email:</strong> @Email</div>
            <div class="col-md-6"><strong>Phone:</strong> @Phone</div>
            <div class="col-md-6"><strong>Address:</strong> @Address</div>
        </div>
    </div>
</div>

<!-- Work History -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <a href="" @onclick="() => OnEdit.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-2 border-bottom">
                <div><strong>@entry.Title</strong> at @entry.Company</div>
                <div class="text-muted small">
                    @entry.StartDate.ToString("MMM yyyy") –
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <div class="mt-1">@entry.Description</div>
                }
            </div>
        }
    </div>
</div>

<!-- References -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <a href="" @onclick="() => OnEdit.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
            </div>
        }
    </div>
</div>

<!-- Cover Letter -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <a href="" @onclick="() => OnEdit.InvokeAsync(4)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? SubmitError { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
}

