            var workHistory = new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    public class WorkEntryModel
