toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_fa3ff468c69344bb88e04db9a79ad9e1.Models
@using sv_fa3ff468c69344bb88e04db9a79ad9e1.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1 class="mb-4">Job Application</h1>

@if (_submitted)
{
    <div class="alert alert-success text-center py-5">
        <h2>🎉 Application Submitted!</h2>
        <p class="lead mt-3">Your application has been received.</p>
        <p>Application ID: <strong>@_applicationId</strong></p>
    </div>
}
else
{
    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="card mt-4">
        <div class="card-body">
            @switch (_currentStep)
            {
                case 1:
                    <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                      FullNameChanged="v => _fullName = v"
                                      EmailChanged="v => _email = v"
                                      PhoneChanged="v => _phone = v"
                                      AddressChanged="v => _address = v"
                                      ValidationError="@_validationError"
                                      OnNext="HandlePersonalInfoNext" />
                    break;

                case 2:
                    <StepWorkHistory WorkEntries="_workEntries"
                                     ValidationError="@_validationError"
                                     OnBack="GoBack"
                                     OnNext="HandleWorkHistoryNext" />
                    break;

                case 3:
                    <StepReferences References="_references"
                                    ValidationError="@_validationError"
                                    OnBack="GoBack"
                                    OnNext="HandleReferencesNext" />
                    break;

                case 4:
                    <StepCoverLetter @bind-CoverLetter="_coverLetter"
                                     MaxLength="2000"
                                     ValidationError="@_validationError"
                                     OnBack="GoBack"
                                     OnNext="HandleCoverLetterNext" />
                    break;

                case 5:
                    <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                WorkEntries="_workEntries"
                                References="_references"
                                CoverLetter="@_coverLetter"
                                IsSubmitting="_isSubmitting"
                                SubmitError="@_submitError"
                                OnEdit="GoToStep"
                                OnSubmit="HandleSubmit" />
                    break;
            }
        </div>
    </div>
}

@code {
    private int _currentStep = 1;
    private readonly HashSet<int> _completedSteps = new();
    private string? _validationError;

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string _coverLetter = "";

    // Submit
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _submitError;

    private void GoToStep(int step)
    {
        if (step < _currentStep || _completedSteps.Contains(step))
        {
            _validationError = null;
            _currentStep = step;
        }
    }

    private void GoBack()
    {
        _validationError = null;
        _currentStep--;
    }

    private void AdvanceTo(int step)
    {
        _completedSteps.Add(_currentStep);
        _validationError = null;
        _currentStep = step;
    }

    private async Task HandlePersonalInfoNext()
    {
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _validationError = "All fields are required.";
            return;
        }

        var emailValid = await ApplicationService.ValidateEmailAsync(_email);
        if (!emailValid)
        {
            _validationError = "Please enter a valid email address.";
            return;
        }

        AdvanceTo(2);
    }

    private void HandleWorkHistoryNext()
    {
        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                _validationError = "Company, job title, and start date are required for each entry.";
                return;
            }
        }
        AdvanceTo(3);
    }

    private void HandleReferencesNext()
    {
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _validationError = "All fields are required for each reference.";
                return;
            }
        }
        AdvanceTo(4);
    }

    private void HandleCoverLetterNext()
    {
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _validationError = "Please write a cover letter.";
            return;
        }
        AdvanceTo(5);
    }

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        _submitError = null;

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
